/**
 * @summary Get complaint analytics
 */
export const getGetComplaintAnalyticsUrl = (
  params?: GetComplaintAnalyticsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/analytics/complaints?${stringifiedParams}`
    : `/api/analytics/complaints`;
};

export const getComplaintAnalytics = async (
  params?: GetComplaintAnalyticsParams,
  options?: RequestInit,
): Promise<ComplaintAnalytics> => {
  return customFetch<ComplaintAnalytics>(getGetComplaintAnalyticsUrl(params), {
    ...options,
    method: "GET",
  });
};

